```python
import ast
import os
import json

def extract_todos(file_path):
    try:
        with open(file_path, 'r') as file:
            tree = ast.parse(file.read())
        todos = []
        for node in ast.walk(tree):
            if isinstance(node, ast.FunctionDef):
                for line in node.body:
                    if isinstance(line, ast.Expr) and isinstance(line.value, ast.Constant) and isinstance(line.value.value, str) and 'TODO' in line.value.value:
                        todos.append({'file': file_path, 'function_name': node.name, 'line_number': line.lineno})
        return todos
    except Exception as e:
        print(f'Error parsing {file_path}: {e}')
        return []

todos = []
for root, dirs, files in os.walk('.'):
    for file in files:
        if file.endswith('.py'):
            file_path = os.path.join(root, file)
            todos.extend(extract_todos(file_path))

print(json.dumps(todos, indent=4))
```

This code should correctly identify TODO comments within Python functions in the workspace directory. Note that this code checks for TODO comments in string literals within the functions. If you need to check for TODO comments in other types of nodes (e.g., comments), you would need to modify the code accordingly.
